DROP MATERIALIZED VIEW "public"."view__model_stats_by_device";--> statement-breakpoint
CREATE MATERIALIZED VIEW "public"."view__model_stats_by_device" AS (select "models"."id" as "model_id", "models"."display_name", "models"."format", "models"."parameters", "models"."quant", "models"."architecture", "models"."source", "devices"."chip_id", MIN("devices"."cpu") as "device_cpu", MIN("devices"."cpu_cores") as "device_cpu_cores", MIN("devices"."gpu") as "device_gpu", MIN("devices"."gpu_cores") as "device_gpu_cores", MIN("devices"."ram_gb") as "device_ram_gb", "runs"."runtime_name", count(distinct "runs"."id") as "run_count", count("trials"."id") as "trial_count", PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY "trials"."ttft_ms") as "ttft_p50_ms", PERCENTILE_CONT(0.95) WITHIN GROUP (ORDER BY "trials"."ttft_ms") as "ttft_p95_ms", AVG("trials"."decode_tps") as "avg_decode_tps", AVG("trials"."prefill_tps") as "avg_prefill_tps", AVG("trials"."idle_rss_mb") as "avg_idle_rss_mb", AVG("trials"."peak_rss_mb") as "avg_peak_rss_mb" from "trials" inner join "runs" on "trials"."run_id" = "runs"."id" inner join "models" on "runs"."model_id" = "models"."id" inner join "devices" on "runs"."device_id" = "devices"."id" where ("runs"."status" = 'verified' and "trials"."input_tokens" = 4096 and "trials"."output_tokens" = 1024) group by "models"."id", "devices"."chip_id", "runs"."runtime_name");